def count_unique(nums):
    if not nums:
        return 0
    count_dict = {}
    for num in nums:
        if num in count_dict:
            count_dict[num] += 1
        else:
            count_dict[num] = 1
    unique_count = sum(1 for v in count_dict.values() if v == 1)
    return unique_count
